<template>
    <div class="page_path">
        <img src="@/assets/nav_home.svg" />
        <span class="depth01">{{ path.depth01 }}</span>
        <span v-if="path.depth02" class="depth02">{{ path.depth02 }}</span>
        <span v-if="path.depth03" class="depth03">{{ path.depth03 }}</span>
    </div>
</template>

<script>
import { historyMenu, settingMenu } from '@/data/menuList';
export default {
    data: () => ({
        path: {
            depth01: '',
            depth02: '',
            depth03: null,
        },
    }),
    watch: {
        $route(to, from) {
            this.setPath();
        },
    },
    mounted() {
        this.setPath();
    },
    methods: {
        setPath() {
            const menuList = historyMenu.concat(settingMenu);
            const currentRoute = this.$route;
            if (currentRoute.path.includes('history')) {
                this.path.depth01 = '히스토리';
            } else if (currentRoute.path.includes('setting')) {
                this.path.depth01 = '설정 ';
            } else if (currentRoute.path.includes('account')) {
                this.path.depth01 = '계정관리 ';
            }
            menuList.find((menu) => {
                if (menu.router === currentRoute.path) {
                    this.path.depth02 = menu.title;
                }
            });
            this.path.depth03 = null;
            switch (currentRoute.path) {
                case '/setting/map/fence':
                    this.path.depth02 = '지도';
                    this.path.depth03 = '울타리';
                    break;
                case '/setting/map/circle':
                    this.path.depth02 = '지도';
                    this.path.depth03 = '사용자(중심)';
                    break;
                case '/setting/map/detection':
                    this.path.depth02 = '지도';
                    this.path.depth03 = '드론 탐지 창';
                    break;
                case '/setting/map/spooper':
                    this.path.depth02 = '지도';
                    this.path.depth03 = '스푸퍼';
                    break;
                case '/setting/device/scanner':
                    this.path.depth02 = '장비 별 설정';
                    this.path.depth03 = '스캐너';
                    break;
                case '/setting/device/dronedome':
                    this.path.depth02 = '장비 별 설정';
                    this.path.depth03 = '드론돔';
                    break;
                case '/setting/device/spoofer':
                    this.path.depth02 = '장비 별 설정';
                    this.path.depth03 = '스푸퍼';
                    break;

                default:
                    break;
            }
        },
    },
};
</script>

<style lang="scss" scoped>
.page_path {
    display: flex;
    align-items: flex-end;
    width: 100%;
    height: 60px;
    padding: 0 20px 10px;
    background: #d7d7d7;
    border-bottom: 1px solid #b6b6b6;
    color: $color-main02;
    img {
        margin-right: 10px;
    }

    .depth01 {
        font: {
            size: 20px;
        }
    }
    .depth02 {
        &::before {
            display: inline-block;
            content: '>';
            padding: 0 5px;
            font: {
                size: 20px;
                weight: 400;
            }
        }
    }
    .depth03 {
        &::before {
            display: inline-block;
            content: '>';
            padding: 0 5px;
        }
    }
    .depth02,
    .depth03 {
        font: {
            size: 25px;
            weight: 600;
        }
    }
}
</style>
