<template>
    <v-container>
        <PagePath />
        <div class="content">
            <div class="table_wrap">
                <h4>드론 탐지 구역 알람</h4>
                <div>
                    <v-data-table :headers="headers" :items="dataList" no-data-text="데이터가 존재하지 않습니다." hide-default-footer>
                        <template #item="{ item }">
                            <tr>
                                <td>{{ item.ROW_NO }}</td>
                                <td>{{ item.RADIUS_NAME }}</td>
                                <td>{{ item.RADIUS }}</td>
                                <!-- <td>{{ item.ALARM_FILE_URI }}</td> -->
                                <td>
                                    <input ref="fileInput" type="file" accept=".pdf" @change="onChangeFiles($event, idx)" />
                                    <!-- <template v-if="item.FILE_NAME == null">
                                    <span class="none-file grey--text text--lighten-5 font-weight-light">첨부된 파일이 없습니다.</span>
                                  </template>
                                  <template v-else>
                                    <v-chip close @click:close="item.FILE_NAME = null">{{ item.FILE_NAME }}</v-chip>
                                  </template> -->
                                </td>
                                <td>
                                    <button @click="doPlayAudio(item)">
                                        <img src="@/assets/setting/ico_listening.svg" />
                                    </button>
                                    <!-- <audio :src="item.file"></audio> -->
                                </td>
                                <!-- <td><v-checkbox :value="item.ALARM_YN" @click="selectList()" /></td> -->
                                <td><v-checkbox v-model="item.ALARM_YN" /></td>
                            </tr>
                        </template>
                    </v-data-table>
                </div>
            </div>
            <div class="btn_area">
                <!-- <v-btn elevation="3" color="primary" @click="checkData()"> 확인 </v-btn> -->
                <v-btn elevation="3" color="primary" @click="doSaveMulti"> 확인 </v-btn>
            </div>
        </div>
        <AlertModal :params="alertModalParams"></AlertModal>
    </v-container>
</template>

<script>
import cautionList from '@/data/cautionList';
import PagePath from '@/components/widget/PagePath';

import * as Consts from '@/common/Consts';
import * as LogUtil from '@/common/LogUtil';
import * as AlarmConfig from '@/rest/AlarmConfig';

import AlertModal from '@/components/modal/AlertModal';

export default {
    components: {
        PagePath,
        AlertModal,
    },
    data: () => ({
        alertModalParams: { isOpened: false, title: '', message: '' },
        dataList: [],
        selectInfo: [],
        checkNum: [],
        headers: [
            { text: '단계', value: 'ROW_NO', width: '80' },
            { text: '이름', value: 'RADIUS_NAME', sortable: false, width: '200' },
            { text: '범위(m)', value: 'RADIUS', width: '100' },
            { text: '알람소리 파일', value: 'ALARM_FILE_URI', sortable: false },
            { text: '듣기', value: 'listening', sortable: false },
            { text: '알림음', value: 'ALARM_YN' },
        ],
        audio: null,
    }),
    beforeMount() {
        // this.cautionList = cautionList;
        this.initDataList();
    },
    methods: {
        showAlertModal(msg) {
            this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
        },
        selectList() {
            setTimeout(() => {
                this.checkNum = document.querySelectorAll('input[type="checkbox"]:checked');
            }, 100);
        },
        checkData() {
            this.selectInfo = [];
            this.checkNum.forEach((checked) => {
                this.cautionList.map((item) => {
                    if (item.idx === checked.value * 1) this.selectInfo.push(item);
                });
            });
        },
        doPlayAudio(item) {
            if (this.audio != null) this.audio.pause();
            this.audio = new Audio(Consts.SERVER_URL + item.ALARM_FILE_URI);
            this.audio.play();
        },
        initDataList(condition) {
            let options = {
                conditions: [
                    // { clause: 'and', name: 'MEMBER_TYPE', operator: '=', value: 'H'},
                ],
                orderBys: [{ name: 'RADIUS', operator: 'asc' }],
                paging: { pageNo: 1, pageSize: 100 },
            };
            if (condition != null) options.conditions.push(condition);

            AlarmConfig.listByCondition(options)
                .then((res) => {
                    if (res.data.RES_CODE >= 0) {
                        this.dataList = res.data.ITEMS;
                        this.dataList.forEach((item, index) => {
                            item.ROW_NO = index + 1;
                        });
                        LogUtil.debug('this.dataList=', this.dataList);
                    } else {
                        this.showAlertModal(res.data.RES_MSG);
                    }
                })
                .catch((e) => {
                    LogUtil.error('error=', e);
                    this.showAlertModal(e);
                })
                .finally(() => {});
        },
        doSaveMulti() {
            let dataList = [];
            this.dataList.forEach((item) => {
                dataList.push({
                    ALARM_CONFIG_ID: item.ALARM_CONFIG_ID,
                    MAP_CONFIG_CIRCLE_ID: item.MAP_CONFIG_CIRCLE_ID,
                    ALARM_FILE_URI: item.ALARM_FILE_URI,
                    ALARM_YN: item.ALARM_YN !== null ? item.ALARM_YN : 0,
                });
            });
            LogUtil.debug('doSaveMulti(): dataList=', dataList);

            AlarmConfig.saveMulti({
                DATA_LIST: dataList,
            })
                .then((res) => {
                    if (res.data.RES_CODE >= 0) {
                        LogUtil.debug('res.data=', res.data);
                    } else {
                        this.showAlertModal(res.data.RES_MSG);
                    }
                })
                .catch((e) => {
                    LogUtil.error('error=', e);
                    this.showAlertModal(e);
                })
                .finally(() => {});
        },
    },
};
</script>

<style lang="scss" scoped>
.content {
    .table_wrap {
        width: 1000px;
        border: 1px solid $color-main03;
        border-radius: 10px;
        margin: 60px auto 0;
        & > div {
            padding: 31px 50px 48px;
        }
        h4 {
            @include centerAlign();
            height: 60px;
            border-bottom: 1px solid $color-main03;
            font: {
                size: 20px;
                weight: 600;
            }
        }
    }
    .btn_area {
        @include centerAlign();
        width: 100%;
        margin-top: 50px;
    }
}
</style>
